CREATE OR REPLACE FUNCTION sync_module_study_to_study() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO study ( study_id, parent_study_id, unique_identifier, secondary_identifier, name, summary, date_planned_start, date_planned_end, date_created, date_updated, owner_id, update_id, type_id, status_id, principal_investigator, facility_name, facility_city, facility_state, facility_zip, facility_country, facility_recruitment_status, facility_contact_name, facility_contact_degree, facility_contact_phone, facility_contact_email, protocol_type, protocol_description, protocol_date_verification, phase, expected_total_enrollment, sponsor, collaborators, medline_identifier, url, url_description, conditions, keywords, eligibility, gender, age_max, age_min, healthy_volunteer_accepted, purpose, allocation, masking, control, assignment, endpoint, interventions, duration, selection, timing, official_title, results_reference, oc_oid, old_status_id, "version", feature_flags ) VALUES ( NEW.study_id, NEW.parent_study_id, NEW.unique_identifier, NEW.secondary_identifier, NEW.name, NEW.summary, NEW.date_planned_start, NEW.date_planned_end, NEW.date_created, NEW.date_updated, NEW.owner_id, NEW.update_id, NEW.type_id, NEW.status_id, NEW.principal_investigator, NEW.facility_name, NEW.facility_city, NEW.facility_state, NEW.facility_zip, NEW.facility_country, NEW.facility_recruitment_status, NEW.facility_contact_name, NEW.facility_contact_degree, NEW.facility_contact_phone, NEW.facility_contact_email, NEW.protocol_type, NEW.protocol_description, NEW.protocol_date_verification, NEW.phase, NEW.expected_total_enrollment, NEW.sponsor, NEW.collaborators, NEW.medline_identifier, NEW.url, NEW.url_description, NEW.conditions, NEW.keywords, NEW.eligibility, NEW.gender, NEW.age_max, NEW.age_min, NEW.healthy_volunteer_accepted, NEW.purpose, NEW.allocation, NEW.masking, NEW.control, NEW.assignment, NEW.endpoint, NEW.interventions, NEW.duration, NEW.selection, NEW.timing, NEW.official_title, NEW.results_reference, NEW.oc_oid, NEW.old_status_id, NEW."version", COALESCE(NEW.feature_flags, '{}'::jsonb) ) ON CONFLICT (study_id) DO UPDATE SET parent_study_id = EXCLUDED.parent_study_id, unique_identifier = EXCLUDED.unique_identifier, secondary_identifier = EXCLUDED.secondary_identifier, name = EXCLUDED.name, summary = EXCLUDED.summary, date_planned_start = EXCLUDED.date_planned_start, date_planned_end = EXCLUDED.date_planned_end, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, owner_id = EXCLUDED.owner_id, update_id = EXCLUDED.update_id, type_id = EXCLUDED.type_id, status_id = EXCLUDED.status_id, principal_investigator = EXCLUDED.principal_investigator, facility_name = EXCLUDED.facility_name, facility_city = EXCLUDED.facility_city, facility_state = EXCLUDED.facility_state, facility_zip = EXCLUDED.facility_zip, facility_country = EXCLUDED.facility_country, facility_recruitment_status = EXCLUDED.facility_recruitment_status, facility_contact_name = EXCLUDED.facility_contact_name, facility_contact_degree = EXCLUDED.facility_contact_degree, facility_contact_phone = EXCLUDED.facility_contact_phone, facility_contact_email = EXCLUDED.facility_contact_email, protocol_type = EXCLUDED.protocol_type, protocol_description = EXCLUDED.protocol_description, protocol_date_verification = EXCLUDED.protocol_date_verification, phase = EXCLUDED.phase, expected_total_enrollment = EXCLUDED.expected_total_enrollment, sponsor = EXCLUDED.sponsor, collaborators = EXCLUDED.collaborators, medline_identifier = EXCLUDED.medline_identifier, url = EXCLUDED.url, url_description = EXCLUDED.url_description, conditions = EXCLUDED.conditions, keywords = EXCLUDED.keywords, eligibility = EXCLUDED.eligibility, gender = EXCLUDED.gender, age_max = EXCLUDED.age_max, age_min = EXCLUDED.age_min, healthy_volunteer_accepted = EXCLUDED.healthy_volunteer_accepted, purpose = EXCLUDED.purpose, allocation = EXCLUDED.allocation, masking = EXCLUDED.masking, control = EXCLUDED.control, assignment = EXCLUDED.assignment, endpoint = EXCLUDED.endpoint, interventions = EXCLUDED.interventions, duration = EXCLUDED.duration, selection = EXCLUDED.selection, timing = EXCLUDED.timing, official_title = EXCLUDED.official_title, results_reference = EXCLUDED.results_reference, oc_oid = EXCLUDED.oc_oid, old_status_id = EXCLUDED.old_status_id, "version" = EXCLUDED."version", feature_flags = COALESCE(EXCLUDED.feature_flags, '{}'::jsonb); RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE study SET parent_study_id = NEW.parent_study_id, unique_identifier = NEW.unique_identifier, secondary_identifier = NEW.secondary_identifier, name = NEW.name, summary = NEW.summary, date_planned_start = NEW.date_planned_start, date_planned_end = NEW.date_planned_end, date_created = NEW.date_created, date_updated = NEW.date_updated, owner_id = NEW.owner_id, update_id = NEW.update_id, type_id = NEW.type_id, status_id = NEW.status_id, principal_investigator = NEW.principal_investigator, facility_name = NEW.facility_name, facility_city = NEW.facility_city, facility_state = NEW.facility_state, facility_zip = NEW.facility_zip, facility_country = NEW.facility_country, facility_recruitment_status = NEW.facility_recruitment_status, facility_contact_name = NEW.facility_contact_name, facility_contact_degree = NEW.facility_contact_degree, facility_contact_phone = NEW.facility_contact_phone, facility_contact_email = NEW.facility_contact_email, protocol_type = NEW.protocol_type, protocol_description = NEW.protocol_description, protocol_date_verification = NEW.protocol_date_verification, phase = NEW.phase, expected_total_enrollment = NEW.expected_total_enrollment, sponsor = NEW.sponsor, collaborators = NEW.collaborators, medline_identifier = NEW.medline_identifier, url = NEW.url, url_description = NEW.url_description, conditions = NEW.conditions, keywords = NEW.keywords, eligibility = NEW.eligibility, gender = NEW.gender, age_max = NEW.age_max, age_min = NEW.age_min, healthy_volunteer_accepted = NEW.healthy_volunteer_accepted, purpose = NEW.purpose, allocation = NEW.allocation, masking = NEW.masking, control = NEW.control, assignment = NEW.assignment, endpoint = NEW.endpoint, interventions = NEW.interventions, duration = NEW.duration, selection = NEW.selection, timing = NEW.timing, official_title = NEW.official_title, results_reference = NEW.results_reference, oc_oid = NEW.oc_oid, old_status_id = NEW.old_status_id, "version" = NEW."version", feature_flags = COALESCE(NEW.feature_flags, '{}'::jsonb) WHERE study_id = OLD.study_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM study WHERE study_id = OLD.study_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
CREATE OR REPLACE FUNCTION sync_study_to_module_study() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
