.feature_flags ) ON CONFLICT (study_id) DO UPDATE SET parent_study_id = EXCLUDED.parent_study_id, unique_identifier = EXCLUDED.unique_identifier, secondary_identifier = EXCLUDED.secondary_identifier, name = EXCLUDED.name, summary = EXCLUDED.summary, date_planned_start = EXCLUDED.date_planned_start, date_planned_end = EXCLUDED.date_planned_end, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, owner_id = EXCLUDED.owner_id, update_id = EXCLUDED.update_id, type_id = EXCLUDED.type_id, status_id = EXCLUDED.status_id, principal_investigator = EXCLUDED.principal_investigator, facility_name = EXCLUDED.facility_name, facility_city = EXCLUDED.facility_city, facility_state = EXCLUDED.facility_state, facility_zip = EXCLUDED.facility_zip, facility_country = EXCLUDED.facility_country, facility_recruitment_status = EXCLUDED.facility_recruitment_status, facility_contact_name = EXCLUDED.facility_contact_name, facility_contact_degree = EXCLUDED.facility_contact_degree, facility_contact_phone = EXCLUDED.facility_contact_phone, facility_contact_email = EXCLUDED.facility_contact_email, protocol_type = EXCLUDED.protocol_type, protocol_description = EXCLUDED.protocol_description, protocol_date_verification = EXCLUDED.protocol_date_verification, phase = EXCLUDED.phase, expected_total_enrollment = EXCLUDED.expected_total_enrollment, sponsor = EXCLUDED.sponsor, collaborators = EXCLUDED.collaborators, medline_identifier = EXCLUDED.medline_identifier, url = EXCLUDED.url, url_description = EXCLUDED.url_description, conditions = EXCLUDED.conditions, keywords = EXCLUDED.keywords, eligibility = EXCLUDED.eligibility, gender = EXCLUDED.gender, age_max = EXCLUDED.age_max, age_min = EXCLUDED.age_min, healthy_volunteer_accepted = EXCLUDED.healthy_volunteer_accepted, purpose = EXCLUDED.purpose, allocation = EXCLUDED.allocation, masking = EXCLUDED.masking, control = EXCLUDED.control, assignment = EXCLUDED.assignment, endpoint = EXCLUDED.endpoint, interventions = EXCLUDED.interventions, duration = EXCLUDED.duration, selection = EXCLUDED.selection, timing = EXCLUDED.timing, official_title = EXCLUDED.official_title, results_reference = EXCLUDED.results_reference, oc_oid = EXCLUDED.oc_oid, old_status_id = EXCLUDED.old_status_id, "version" = EXCLUDED."version", feature_flags = EXCLUDED.feature_flags; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE module_study SET parent_study_id = NEW.parent_study_id, unique_identifier = NEW.unique_identifier, secondary_identifier = NEW.secondary_identifier, name = NEW.name, summary = NEW.summary, date_planned_start = NEW.date_planned_start, date_planned_end = NEW.date_planned_end, date_created = NEW.date_created, date_updated = NEW.date_updated, owner_id = NEW.owner_id, update_id = NEW.update_id, type_id = NEW.type_id, status_id = NEW.status_id, principal_investigator = NEW.principal_investigator, facility_name = NEW.facility_name, facility_city = NEW.facility_city, facility_state = NEW.facility_state, facility_zip = NEW.facility_zip, facility_country = NEW.facility_country, facility_recruitment_status = NEW.facility_recruitment_status, facility_contact_name = NEW.facility_contact_name, facility_contact_degree = NEW.facility_contact_degree, facility_contact_phone = NEW.facility_contact_phone, facility_contact_email = NEW.facility_contact_email, protocol_type = NEW.protocol_type, protocol_description = NEW.protocol_description, protocol_date_verification = NEW.protocol_date_verification, phase = NEW.phase, expected_total_enrollment = NEW.expected_total_enrollment, sponsor = NEW.sponsor, collaborators = NEW.collaborators, medline_identifier = NEW.medline_identifier, url = NEW.url, url_description = NEW.url_description, conditions = NEW.conditions, keywords = NEW.keywords, eligibility = NEW.eligibility, gender = NEW.gender, age_max = NEW.age_max, age_min = NEW.age_min, healthy_volunteer_accepted = NEW.healthy_volunteer_accepted, purpose = NEW.purpose, allocation = NEW.allocation, masking = NEW.masking, control 