DROP TRIGGER IF EXISTS trg_sync_module_study ON module_study; CREATE TRIGGER trg_sync_module_study AFTER INSERT OR UPDATE OR DELETE ON module_study FOR EACH ROW EXECUTE FUNCTION sync_module_study_to_study();
DROP TRIGGER IF EXISTS trg_sync_study_to_module ON study; CREATE TRIGGER trg_sync_study_to_module AFTER INSERT OR UPDATE OR DELETE ON study FOR EACH ROW EXECUTE FUNCTION sync_study_to_module_study();
